        { 
          text: "Salir", 
          style: "destructive", 
          onPress: () => {
            const token = getToken();
            if (token) {
              // Intentar cerrar sesión en servidor sin bloquear la UI
              logout(token).catch(err => console.error("Error cierre sesión remoto:", err));
            }

            // Limpiar token local y navegar inmediatamente
            setToken(null);
            navigation.dispatch(
              CommonActions.reset({
