    backgroundColor: 'rgba(28, 39, 63, 0.1)', 
    justifyContent: 'center', 
    alignItems: 'center' 
  },
  menuLabel: { fontSize: 15, fontWeight: '600', color: '#101828' },
  menuSubtitle: { fontSize: 12, color: '#6B7280' },
  preferenceRow: { 
    flexDirection: 'row', 
    alignItems: 'center', 
    padding: 16 
  },
  logoutBtn: { 
    flexDirection: 'row', 
    alignItems: 'center', 
    backgroundColor: '#FFF', 
    padding: 16, 
    borderRadius: 12, 
    borderWidth: 1, 
    borderColor: '#E5E7EB', 
    gap: 16 
  },
  logoutIconBox: { 
    width: 40, 
    height: 40, 
    borderRadius: 8, 
    backgroundColor: '#FEE2E2', 
    justifyContent: 'center', 
    alignItems: 'center' 
  },
  logoutText: { flex: 1, fontSize: 15, fontWeight: '600', color: '#DC2626' },
  footer: { marginTop: 8, alignItems: 'center' },
  footerText: { fontSize: 12, color: '#9CA3AF' }
});

import { NavLink, useNavigate } from "react-router-dom";
import logo from "/src/assets/LogoPI.png";

const menuItems = [
  { to: "/dashboard", label: "Inicio" },
  { to: "/inventario", label: "Inventario / Almacen" },
  { to: "/compras", label: "Compras" },
  { to: "/ventas", label: "Ventas" },
  { to: "/clientes", label: "Clientes" },
  { to: "/proveedores", label: "Proveedores" },
  { to: "/facturacion", label: "Facturacion" },
  { to: "/reportes", label: "Reportes" },
];

export default function Sidebar() {
  const navigate = useNavigate();
  const rolUsuario = localStorage.getItem("rolUsuario");

  const menuVisible =
    rolUsuario === "Vendedor"
      ? menuItems.filter((item) => item.to === "/ventas" || item.to === "/reportes")
      : rolUsuario === "Comprador"
        ? menuItems.filter((item) => item.to === "/compras")
      : menuItems;

  const cerrarSesion = async () => {
    try {
      const token = localStorage.getItem("token");
      if (token) {
        await fetch("http://localhost:8000/api/v1/auth/logout", {
          method: "POST",
          headers: {
            "Authorization": `Bearer ${token}`,
            "Accept": "application/json",
          },
        });
      }
    } catch (error) {
      console.error("Error al cerrar sesión en el servidor:", error);
    } finally {
      localStorage.removeItem("rolUsuario");
      localStorage.removeItem("token");
      navigate("/");
    }
  };

  return (
    <aside className="sidebar">
      <div className="sidebar-logo">
        <img src={logo} alt="Logo del proyecto" className="project-logo" />
      </div>

      <nav className="sidebar-menu" aria-label="Navegacion principal">
        {menuVisible.map((item) => (
          <NavLink
            key={item.to}
            to={item.to}
            className={({ isActive }) => (isActive ? "active" : "")}
          >
            {item.label}
          </NavLink>
        ))}

        <div className="sidebar-footer">
          <div className="sidebar-divider" />

          {rolUsuario === "Administrador" ? (
            <NavLink
              to="/configuracion"
              className={({ isActive }) => `sidebar-action${isActive ? " active" : ""}`}
            >
              Configuracion
            </NavLink>
          ) : null}

          <button type="button" className="sidebar-action" onClick={cerrarSesion}>
            Cerrar sesion
          </button>
        </div>
      </nav>
    </aside>
  );
}

